                )
            }
        }
    }

    /// Returns the severity used by the reference for the mod-manager row.
    pub const fn severity(&self) -> StatusSeverity {
        match self {
            Self::NotFound => StatusSeverity::Error,
            Self::Detected(_) => StatusSeverity::Neutral,
        }
    }
