        let desktop = FakeDesktopActions::default().fail(
            PlatformOperation::LaunchTool,
            r"C:\Tools\BSArch.exe",
            PlatformErrorKind::NotFound,
        );

        let result = desktop.launch_tool(Path::new(r"C:\Tools\BSArch.exe"), &[]);

        assert!(!result.is_success());
        assert_eq!(result.operation, PlatformOperation::LaunchTool);
        assert_eq!(result.failure_kind(), Some(PlatformErrorKind::NotFound));
        assert_eq!(result.safe_message(), "Tool launch failed.");
    }

    #[cfg(not(windows))]
    #[test]
    fn real_desktop_actions_are_explicitly_unsupported_off_windows() {
        let desktop = RealDesktopActions::new();

        let url_result = desktop.open_url("https://example.invalid");
        let path_result = desktop.open_path(Path::new("Data"));
        let launch_result = desktop.launch_tool(Path::new("xEdit.exe"), &[]);

        assert_eq!(
            url_result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
        );
        assert_eq!(
            path_result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
        );
        assert_eq!(
            launch_result.failure_kind(),
            Some(PlatformErrorKind::UnsupportedPlatform)
        );
        assert_eq!(
            url_result.safe_message(),
            "URL open is not supported on this platform."
        );
    }
}

//! Testable Overview-tab controller and worker payload reducer.
//!
//! The controller owns no Slint handles and performs no filesystem, registry,
//! process, network, or desktop work. It only turns UI intents and owned worker
//! events into a current [`OverviewSnapshot`](crate::domain::overview::OverviewSnapshot)
//! so production code can keep slow work on background workers while tests can
//! exercise every state transition with in-memory values.

use crate::{
    domain::{
        overview::{
            OverviewActionError, OverviewDeferredAction, OverviewDeferredActionKind,
            OverviewDeferredActionTarget, OverviewGamePathStatus, OverviewSnapshot,
            UpdateBannerState, UpdateProvider,
        },
        settings::UpdateSource,
    },
    workers::{
        OverviewWorkerPayload, WorkerEvent, WorkerFailure, WorkerPayload, WorkerSpawnError,
        WorkerTask, WorkerTaskId, WorkerTaskKind, WorkerTaskStatus,
    },
};

/// Stable prefix for Overview refresh worker task identifiers.
pub const OVERVIEW_REFRESH_TASK_PREFIX: &str = "overview-refresh";
/// Stable prefix for Overview update-check worker task identifiers.
pub const OVERVIEW_UPDATE_TASK_PREFIX: &str = "overview-update";
/// Stable prefix for Overview desktop-action worker task identifiers.
pub const OVERVIEW_DESKTOP_TASK_PREFIX: &str = "overview-desktop";

/// Monotonic identity assigned to each Overview refresh request.
pub type OverviewRefreshId = u64;

/// Result of applying a controller transition.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum OverviewTransitionResult {
    /// The event matched the active controller state and changed the snapshot or diagnostics.
    Applied,
    /// The event belonged to an older refresh and was intentionally ignored.
    StaleIgnored,
    /// The event was not an Overview event or was not relevant to this reducer.
    Ignored,
}

impl OverviewTransitionResult {
    /// Returns true when the event changed controller state.
    pub const fn is_applied(self) -> bool {
        matches!(self, Self::Applied)
    }
}

/// Work request returned by refresh intents and consumed by worker wiring.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct OverviewRefreshRequest {
    /// Monotonic refresh request id used to reject stale worker results.
    pub refresh_id: OverviewRefreshId,
    /// Update source snapshot captured at request time.
    pub update_source: UpdateSource,
}

impl OverviewRefreshRequest {
    /// Returns whether this refresh should schedule network update work.
    pub const fn should_check_updates(self) -> bool {
        !matches!(self.update_source, UpdateSource::None)
    }

    /// Builds the worker metadata used for the blocking discovery/collection refresh.
    pub fn refresh_task(self) -> WorkerTask {
        overview_refresh_task(self.refresh_id)
    }

    /// Builds the worker metadata used for the async update check tied to this refresh.
    pub fn update_task(self) -> WorkerTask {
        overview_update_task(self.refresh_id)
    }
}

/// Pure reducer for Overview UI state and owned worker events.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct OverviewController {
    snapshot: OverviewSnapshot,
    next_refresh_id: OverviewRefreshId,
    latest_refresh_id: Option<OverviewRefreshId>,
    pending_update_banner: Option<(OverviewRefreshId, UpdateBannerState)>,
}

impl Default for OverviewController {
    fn default() -> Self {
        Self::new()
    }
}

impl OverviewController {
    /// Creates an idle controller with an empty Overview snapshot.
    pub fn new() -> Self {
        Self {
            snapshot: OverviewSnapshot::empty(),
            next_refresh_id: 1,
            latest_refresh_id: None,
            pending_update_banner: None,
        }
    }

    /// Returns the current render-ready Overview snapshot.
    pub fn snapshot(&self) -> &OverviewSnapshot {
        &self.snapshot
    }

    /// Returns the current safe last-action error, if any.
    pub fn last_safe_action_error(&self) -> Option<&OverviewActionError> {
        self.snapshot.last_action_error.as_ref()
    }

    /// Starts the initial loading transition using the supplied settings snapshot.
    pub fn initial_loading(&mut self, update_source: UpdateSource) -> OverviewRefreshRequest {
        self.request_refresh(update_source)
    }

    /// Starts a new refresh and returns the worker request to schedule.
    pub fn request_refresh(&mut self, update_source: UpdateSource) -> OverviewRefreshRequest {
        let refresh_id = self.next_refresh_id;
        self.next_refresh_id = self.next_refresh_id.saturating_add(1);
        self.latest_refresh_id = Some(refresh_id);
        self.pending_update_banner = None;

        let last_action_error = self.snapshot.last_action_error.clone();
        self.snapshot = OverviewSnapshot::loading("Refreshing Overview...");
        self.snapshot.update_banner = initial_update_banner(update_source);
        self.snapshot.last_action_error = last_action_error;

        tracing::info!(
            event = "overview-refresh-requested",
            refresh_id,
            update_source = update_source.as_wire_value(),
            "Overview refresh requested"
        );

        OverviewRefreshRequest {
            refresh_id,
            update_source,
        }
    }

    /// Applies a successful refresh snapshot if it belongs to the latest request.
    pub fn refresh_completed(
        &mut self,
        refresh_id: OverviewRefreshId,
        mut snapshot: OverviewSnapshot,
    ) -> OverviewTransitionResult {
        if !self.is_latest_refresh(refresh_id) {
            tracing::debug!(
                event = "overview-refresh-stale-ignored",
                refresh_id,
                latest_refresh_id = ?self.latest_refresh_id,
                "Ignoring stale Overview refresh result"
            );
            return OverviewTransitionResult::StaleIgnored;
        }

        snapshot.last_action_error = self.snapshot.last_action_error.clone();
        if let Some((pending_refresh_id, update_banner)) = self.pending_update_banner.take() {
            if pending_refresh_id == refresh_id {
                snapshot.update_banner = update_banner;
            } else {
                self.pending_update_banner = Some((pending_refresh_id, update_banner));
            }
        }

        tracing::info!(
            event = "overview-refresh-completed",
            refresh_id,
            phase = ?snapshot.refresh.phase,
            problems = snapshot.problems.len(),
            "Overview refresh completed"
        );
        self.snapshot = snapshot;
        OverviewTransitionResult::Applied
    }

    /// Applies a safe refresh failure if it belongs to the latest request.
    pub fn refresh_failed(
        &mut self,
        refresh_id: OverviewRefreshId,
        failure: WorkerFailure,
    ) -> OverviewTransitionResult {
        if !self.is_latest_refresh(refresh_id) {
            tracing::debug!(
                event = "overview-refresh-failure-stale-ignored",
                refresh_id,
                latest_refresh_id = ?self.latest_refresh_id,
                "Ignoring stale Overview refresh failure"
            );
            return OverviewTransitionResult::StaleIgnored;
        }

        tracing::error!(
            event = "overview-refresh-failed",
            refresh_id,
            safe_message = failure.safe_message(),
            diagnostic = failure.diagnostic().unwrap_or(""),
            "Overview refresh failed"
        );
        let last_action_error = self.snapshot.last_action_error.clone();
        let update_banner = self.snapshot.update_banner.clone();
        self.snapshot = OverviewSnapshot::error(failure.safe_message().to_owned());
        self.snapshot.update_banner = update_banner;
        self.snapshot.last_action_error = last_action_error;
        OverviewTransitionResult::Applied
    }

    /// Maps a worker spawn failure into the safe refresh-failed state.
    pub fn refresh_spawn_failed(
        &mut self,
        refresh_id: OverviewRefreshId,
        error: WorkerSpawnError,
    ) -> OverviewTransitionResult {
        let failure = WorkerFailure::new("Overview refresh could not be started.")
            .with_diagnostic(error.to_string());
        self.refresh_failed(refresh_id, failure)
    }

    /// Applies an update-check banner if it belongs to the latest refresh.
    pub fn update_check_completed(
        &mut self,
        refresh_id: OverviewRefreshId,
        update_banner: UpdateBannerState,
    ) -> OverviewTransitionResult {
        if !self.is_latest_refresh(refresh_id) {
            tracing::debug!(
                event = "overview-update-stale-ignored",
                refresh_id,
                latest_refresh_id = ?self.latest_refresh_id,
                "Ignoring stale Overview update-check result"
            );
            return OverviewTransitionResult::StaleIgnored;
        }

        tracing::info!(
            event = "overview-update-completed",
            refresh_id,
            visible = update_banner.is_visible(),
            "Overview update check completed"
        );

        if self.snapshot.refresh.is_busy() {
            self.pending_update_banner = Some((refresh_id, update_banner));
        } else {
            self.snapshot.update_banner = update_banner;
        }
        OverviewTransitionResult::Applied
    }

    /// Applies desktop action feedback to the safe visible last-action error state.
    pub fn desktop_action_completed(
        &mut self,
        action: OverviewDeferredActionKind,
        error: Option<OverviewActionError>,
    ) -> OverviewTransitionResult {
        if let Some(error) = error {
            tracing::warn!(
                event = "overview-desktop-action-failed",
                action = ?action,
                safe_message = error.summary.as_str(),
                "Overview desktop action failed"
            );
            self.snapshot.last_action_error = Some(error);
        } else {
            tracing::info!(
                event = "overview-desktop-action-completed",
                action = ?action,
                "Overview desktop action completed"
            );
            self.snapshot.last_action_error = None;
        }
        OverviewTransitionResult::Applied
    }

    /// Applies an owned worker event if it carries an Overview payload.
    pub fn handle_worker_event(&mut self, event: WorkerEvent) -> OverviewTransitionResult {
        match event.payload {
            WorkerPayload::Overview(payload) => self.handle_overview_payload(payload),
            WorkerPayload::Error(failure)
                if event.task.kind == WorkerTaskKind::Overview
                    && event.status == WorkerTaskStatus::Failed =>
            {
                let refresh_id = refresh_id_from_task_id(&event.task.id)
                    .or(self.latest_refresh_id)
                    .unwrap_or_default();
                self.refresh_failed(refresh_id, failure)
            }
            _ => OverviewTransitionResult::Ignored,
        }
    }

    /// Returns the current game-path open action when discovery found one.
    pub fn game_path_action(&self) -> Option<OverviewDeferredAction> {
        match &self.snapshot.top.game_path {
            OverviewGamePathStatus::Found(path) => Some(OverviewDeferredAction::open_path(
                OverviewDeferredActionKind::OpenGamePath,
                "Game Path",
                path.clone(),
            )),
            OverviewGamePathStatus::NotFound => None,
        }
    }

    /// Returns the current update-provider action when an update banner is visible.
    pub fn update_provider_action(
        &self,
        provider: UpdateProvider,
    ) -> Option<OverviewDeferredAction> {
        match &self.snapshot.update_banner {
            UpdateBannerState::Available { releases, .. } => releases
                .iter()
                .find(|release| release.provider == provider)
                .map(|release| release.action.clone()),
            UpdateBannerState::Disabled
            | UpdateBannerState::NotChecked { .. }
            | UpdateBannerState::Checking { .. }
            | UpdateBannerState::NoUpdate { .. }
            | UpdateBannerState::FailedSilently { .. } => None,
        }
    }

    fn handle_overview_payload(
        &mut self,
        payload: OverviewWorkerPayload,
    ) -> OverviewTransitionResult {
        match payload {
            OverviewWorkerPayload::RefreshCompleted {
                refresh_id,
                snapshot,
            } => self.refresh_completed(refresh_id, *snapshot),
            OverviewWorkerPayload::UpdateCheckCompleted {
                refresh_id,
                update_banner,
            } => self.update_check_completed(refresh_id, update_banner),
            OverviewWorkerPayload::DesktopActionCompleted { action, error } => {
                self.desktop_action_completed(action, error)
            }
        }
    }

    fn is_latest_refresh(&self, refresh_id: OverviewRefreshId) -> bool {
        self.latest_refresh_id == Some(refresh_id)
    }
}

/// Builds worker metadata for a blocking Overview refresh.
pub fn overview_refresh_task(refresh_id: OverviewRefreshId) -> WorkerTask {
    WorkerTask::new(
        format!("{OVERVIEW_REFRESH_TASK_PREFIX}-{refresh_id}"),
        WorkerTaskKind::Overview,
    )
    .with_label("Refresh Overview")
}

/// Builds worker metadata for an Overview update check.
pub fn overview_update_task(refresh_id: OverviewRefreshId) -> WorkerTask {
    WorkerTask::new(
        format!("{OVERVIEW_UPDATE_TASK_PREFIX}-{refresh_id}"),
        WorkerTaskKind::Overview,
    )
    .with_label("Check Overview updates")
}

/// Builds worker metadata for an Overview desktop action.
pub fn overview_desktop_task(action: OverviewDeferredActionKind) -> WorkerTask {
    WorkerTask::new(
        format!("{OVERVIEW_DESKTOP_TASK_PREFIX}-{}", action_label(action)),
        WorkerTaskKind::DesktopAction,
    )
    .with_label("Open Overview link")
}

/// Converts desktop-action worker output into the Overview payload shape.
pub fn overview_desktop_action_payload(
    action: OverviewDeferredActionKind,
    error: Option<OverviewActionError>,
) -> WorkerPayload {
    WorkerPayload::Overview(OverviewWorkerPayload::desktop_action_completed(
        action, error,
    ))
}

/// Creates a safe action error for an unavailable or unsupported action target.
pub fn unavailable_action_error(
    action: OverviewDeferredActionKind,
    message: impl Into<String>,
) -> OverviewActionError {
    OverviewActionError::new(action, message)
}

/// Returns a safe text representation of an action target for diagnostics.
pub fn action_target_label(action: &OverviewDeferredAction) -> String {
    match &action.target {
        OverviewDeferredActionTarget::Internal => "internal action".to_owned(),
        OverviewDeferredActionTarget::Path(path) => path.display().to_string(),
        OverviewDeferredActionTarget::Url(url) => url.clone(),
    }
}

fn initial_update_banner(update_source: UpdateSource) -> UpdateBannerState {
    if matches!(update_source, UpdateSource::None) {
        UpdateBannerState::Disabled
    } else {
        UpdateBannerState::Checking {
            selected_source: update_source,
        }
    }
}

fn refresh_id_from_task_id(task_id: &WorkerTaskId) -> Option<OverviewRefreshId> {
    task_id
        .as_str()
        .strip_prefix(OVERVIEW_REFRESH_TASK_PREFIX)
        .and_then(|suffix| suffix.strip_prefix('-'))
        .and_then(|value| value.parse::<OverviewRefreshId>().ok())
}

fn action_label(action: OverviewDeferredActionKind) -> &'static str {
    match action {
        OverviewDeferredActionKind::OpenGamePath => "game-path",
        OverviewDeferredActionKind::OpenModManagerDetails => "mod-manager-details",
        OverviewDeferredActionKind::OpenUpdateProvider(UpdateProvider::NexusMods) => "nexus-update",
        OverviewDeferredActionKind::OpenUpdateProvider(UpdateProvider::Github) => "github-update",
        OverviewDeferredActionKind::OpenDowngradeManager => "downgrade-manager",
        OverviewDeferredActionKind::OpenArchivePatcher => "archive-patcher",
        OverviewDeferredActionKind::ShowInvalidModuleVersions => "invalid-module-versions",
        OverviewDeferredActionKind::OpenProblemLink => "problem-link",
    }
}

#[cfg(test)]
mod tests {
    use std::path::PathBuf;

    use super::*;
    use crate::domain::{
        discovery::Fallout4InstallType,
        overview::{OverviewRefreshPhase, OverviewRefreshState, UpdateRelease},
    };

    fn ready_snapshot(message: &str) -> OverviewSnapshot {
        let mut snapshot = OverviewSnapshot::empty();
        snapshot.refresh = OverviewRefreshState::ready(Some(message.to_owned()));
        snapshot.top.version = Fallout4InstallType::OldGen;
        snapshot
    }

    #[test]
    fn overview_controller_initial_loading_sets_busy_snapshot_and_update_check_request() {
        let mut controller = OverviewController::new();

        let request = controller.initial_loading(UpdateSource::Github);

        assert_eq!(request.refresh_id, 1);
        assert!(request.should_check_updates());
        assert_eq!(
            controller.snapshot().refresh.phase,
            OverviewRefreshPhase::Loading
        );
        assert_eq!(
            controller.snapshot().update_banner,
            UpdateBannerState::Checking {
                selected_source: UpdateSource::Github
            }
        );
    }

    #[test]
    fn overview_controller_refresh_success_applies_latest_snapshot() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Nexus);

        let result = controller.refresh_completed(request.refresh_id, ready_snapshot("ready"));

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(
            controller.snapshot().refresh.phase,
            OverviewRefreshPhase::Ready
        );
        assert_eq!(
            controller.snapshot().refresh.message.as_deref(),
            Some("ready")
        );
    }

    #[test]
    fn overview_controller_refresh_failure_maps_to_safe_error_snapshot() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Nexus);

        let result = controller.refresh_failed(
            request.refresh_id,
            WorkerFailure::new("Overview refresh failed.").with_diagnostic("raw detail"),
        );

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(
            controller.snapshot().refresh.phase,
            OverviewRefreshPhase::Error
        );
        assert_eq!(
            controller.snapshot().refresh.message.as_deref(),
            Some("Overview refresh failed.")
        );
    }

    #[test]
    fn overview_controller_update_source_none_skips_update_work() {
        let mut controller = OverviewController::new();

        let request = controller.request_refresh(UpdateSource::None);

        assert!(!request.should_check_updates());
        assert_eq!(
            controller.snapshot().update_banner,
            UpdateBannerState::Disabled
        );
    }

    #[test]
    fn overview_controller_ignores_stale_refresh_when_second_request_is_newer() {
        let mut controller = OverviewController::new();
        let first = controller.request_refresh(UpdateSource::Github);
        let second = controller.request_refresh(UpdateSource::Github);

        let stale = controller.refresh_completed(first.refresh_id, ready_snapshot("first"));
        let latest = controller.refresh_completed(second.refresh_id, ready_snapshot("second"));

        assert_eq!(stale, OverviewTransitionResult::StaleIgnored);
        assert_eq!(latest, OverviewTransitionResult::Applied);
        assert_eq!(
            controller.snapshot().refresh.message.as_deref(),
            Some("second")
        );
    }

    #[test]
    fn overview_controller_update_completed_before_refresh_is_applied_after_refresh() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Github);
        let update_banner = UpdateBannerState::Available {
            selected_source: UpdateSource::Github,
            releases: vec![UpdateRelease::new(UpdateProvider::Github, "9.9.9")],
        };

        let update_result = controller.update_check_completed(request.refresh_id, update_banner);
        assert_eq!(update_result, OverviewTransitionResult::Applied);
        assert!(matches!(
            controller.snapshot().update_banner,
            UpdateBannerState::Checking { .. }
        ));

        controller.refresh_completed(request.refresh_id, ready_snapshot("ready"));

        assert!(matches!(
            controller.snapshot().update_banner,
            UpdateBannerState::Available { ref releases, .. } if releases.len() == 1
        ));
    }

    #[test]
    fn overview_controller_desktop_action_success_clears_last_safe_error() {
        let mut controller = OverviewController::new();
        controller.desktop_action_completed(
            OverviewDeferredActionKind::OpenGamePath,
            Some(OverviewActionError::new(
                OverviewDeferredActionKind::OpenGamePath,
                "Path open failed.",
            )),
        );

        let result =
            controller.desktop_action_completed(OverviewDeferredActionKind::OpenGamePath, None);

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(controller.last_safe_action_error(), None);
    }

    #[test]
    fn overview_controller_desktop_action_failure_updates_last_safe_error() {
        let mut controller = OverviewController::new();

        let result = controller.desktop_action_completed(
            OverviewDeferredActionKind::OpenUpdateProvider(UpdateProvider::NexusMods),
            Some(OverviewActionError::new(
                OverviewDeferredActionKind::OpenUpdateProvider(UpdateProvider::NexusMods),
                "URL open failed.",
            )),
        );

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(
            controller
                .last_safe_action_error()
                .map(|error| error.summary.as_str()),
            Some("URL open failed.")
        );
    }

    #[test]
    fn overview_controller_spawn_failure_maps_to_safe_refresh_error() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Nexus);

        let result = controller.refresh_spawn_failed(
            request.refresh_id,
            WorkerSpawnError::NoActiveRuntime {
                task_id: WorkerTaskId::new("overview-refresh-1"),
            },
        );

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(
            controller.snapshot().refresh.phase,
            OverviewRefreshPhase::Error
        );
        assert_eq!(
            controller.snapshot().refresh.message.as_deref(),
            Some("Overview refresh could not be started.")
        );
    }

    #[test]
    fn overview_controller_worker_panic_failure_event_maps_to_safe_refresh_error() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Nexus);
        let event = WorkerEvent::failed(
            request.refresh_task(),
            WorkerFailure::new("Worker task panicked.").with_diagnostic("boom"),
        );

        let result = controller.handle_worker_event(event);

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(
            controller.snapshot().refresh.phase,
            OverviewRefreshPhase::Error
        );
        assert_eq!(
            controller.snapshot().refresh.message.as_deref(),
            Some("Worker task panicked.")
        );
    }

    #[test]
    fn overview_controller_worker_overview_payload_applies_refresh() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Github);
        let event = WorkerEvent::completed(
            request.refresh_task(),
            WorkerPayload::Overview(OverviewWorkerPayload::refresh_completed(
                request.refresh_id,
                ready_snapshot("from worker"),
            )),
        );

        let result = controller.handle_worker_event(event);

        assert_eq!(result, OverviewTransitionResult::Applied);
        assert_eq!(
            controller.snapshot().refresh.message.as_deref(),
            Some("from worker")
        );
    }

    #[test]
    fn overview_controller_game_path_action_is_available_only_after_path_discovery() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::None);
        let mut snapshot = ready_snapshot("ready");
        snapshot.top.game_path =
            OverviewGamePathStatus::found(PathBuf::from(r"C:\Games\Fallout 4"));
        controller.refresh_completed(request.refresh_id, snapshot);

        let action = controller
            .game_path_action()
            .expect("discovered game path should be openable");

        assert_eq!(action.kind, OverviewDeferredActionKind::OpenGamePath);
        assert!(matches!(
            action.target,
            OverviewDeferredActionTarget::Path(_)
        ));
    }

    #[test]
    fn overview_controller_update_provider_action_tracks_visible_banner() {
        let mut controller = OverviewController::new();
        let request = controller.request_refresh(UpdateSource::Both);
        let mut snapshot = ready_snapshot("ready");
        snapshot.update_banner = UpdateBannerState::Available {
            selected_source: UpdateSource::Both,
            releases: vec![UpdateRelease::new(UpdateProvider::NexusMods, "1.2.3")],
        };
        controller.refresh_completed(request.refresh_id, snapshot);

        assert!(
            controller
                .update_provider_action(UpdateProvider::NexusMods)
                .is_some()
        );
        assert!(
            controller
                .update_provider_action(UpdateProvider::Github)
                .is_none()
        );
    }
}

//! Application-facing shell contracts for the Rust/Slint port.
//!
//! The labels below are copied from the reference `Tab` enum in
//! `CMT/src/enums.py` and the creation order in `CMT/src/cm_checker.py`. They
//! intentionally remain static in Phase 1 so tests can lock the shell identity
//! without launching GUI automation or wiring real tab behavior.

pub mod overview_controller;
pub mod settings_controller;

/// Reference shell tab labels in their display order.
pub const SHELL_TAB_LABELS: [&str; 6] =
    ["Overview", "F4SE", "Scanner", "Tools", "Settings", "About"];

/// Returns the canonical shell tab labels in reference display order.
///
/// The labels match `CMT/src/enums.py` and the notebook construction order in
/// `CMT/src/cm_checker.py`. The function performs no GUI, filesystem, settings,
/// scanner, network, subprocess, or background work.
pub const fn shell_tab_labels() -> [&'static str; 6] {
    SHELL_TAB_LABELS
}

/// No-op application controller boundary reserved for future UI orchestration.
///
/// Phase 1 deliberately keeps this type inert: it owns no settings, platform
/// adapters, worker handles, or Slint component references, and constructing it
/// has no side effects.
#[derive(Debug, Default, Clone, Copy)]
pub struct ShellController;

//! Typed worker event contracts for long-running background operations.
//!
//! The types in this module are owned, `Send`-friendly values that can cross a
//! background-worker boundary before a UI-specific handoff layer decides how to
//! display them. They intentionally avoid Slint handles, models, and borrowed
//! filesystem state.

use std::{
    fmt,
    sync::{
        Arc,
        atomic::{AtomicBool, Ordering},
    },
};

use crate::{
    domain::overview::{
        OverviewActionError, OverviewDeferredActionKind, OverviewSnapshot, UpdateBannerState,
    },
    platform::{
        PlatformError, PlatformErrorKind, PlatformOperation,
        desktop::{DesktopActionOutcome, DesktopActionResult},
    },
};

/// Stable identity for one background task.
#[derive(Debug, Clone, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub struct WorkerTaskId(String);

impl WorkerTaskId {
    /// Creates a task id from a caller-supplied stable identifier.
    pub fn new(id: impl Into<String>) -> Self {
        Self(id.into())
    }

    /// Returns the task id as a borrowed string for logs and diagnostics.
    pub fn as_str(&self) -> &str {
        &self.0
    }
}

impl From<&str> for WorkerTaskId {
    fn from(value: &str) -> Self {
        Self::new(value)
    }
}

impl From<String> for WorkerTaskId {
    fn from(value: String) -> Self {
        Self::new(value)
    }
}

impl fmt::Display for WorkerTaskId {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.as_str())
    }
}

/// High-level category for a background task.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum WorkerTaskKind {
    /// Complete Overview refresh, update-check, or Overview-specific orchestration work.
    Overview,
    /// Fallout 4 installation, manager, registry, process, or system discovery.
    Discovery,
    /// Scanner traversal, parsing, or classification work.
    Scan,
    /// Archive or file patching work.
    Patch,
    /// Network download or update retrieval work.
    Download,
    /// External process execution or monitoring work.
    ExternalProcess,
    /// Desktop handoff such as opening a URL or path.
    DesktopAction,
    /// Generic typed work whose concrete category is not important to the UI.
    Generic,
    /// Unknown work kind retained for forward-compatible handoff.
    Unknown,
}

impl WorkerTaskKind {
    /// Returns a stable label suitable for structured logs and tests.
    pub const fn label(self) -> &'static str {
        match self {
            Self::Overview => "overview",
            Self::Discovery => "discovery",
            Self::Scan => "scan",
            Self::Patch => "patch",
            Self::Download => "download",
            Self::ExternalProcess => "external-process",
            Self::DesktopAction => "desktop-action",
            Self::Generic => "generic",
            Self::Unknown => "unknown",
        }
    }
}

impl fmt::Display for WorkerTaskKind {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.label())
    }
}

/// Shared task metadata attached to every worker event envelope.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct WorkerTask {
    /// Stable task identity chosen by the service that scheduled the work.
    pub id: WorkerTaskId,
    /// High-level work category used by status surfaces.
    pub kind: WorkerTaskKind,
    /// Optional short human-readable label for display surfaces.
    pub label: Option<String>,
}

impl WorkerTask {
    /// Creates a worker task from an id and work kind.
    pub fn new(id: impl Into<WorkerTaskId>, kind: WorkerTaskKind) -> Self {
        Self {
            id: id.into(),
            kind,
            label: None,
        }
    }

    /// Adds a short display label while preserving the stable id.
    pub fn with_label(mut self, label: impl Into<String>) -> Self {
        self.label = Some(label.into());
        self
    }
}

/// Lifecycle/status value for a worker event envelope.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum WorkerTaskStatus {
    /// Task is queued but not running yet.
    Queued,
    /// Task is executing on a worker thread.
    Running,
    /// Task emitted partial progress.
    Progress,
    /// Cancellation was requested by a caller or UI control.
    CancellationRequested,
    /// Worker observed the cancellation request and acknowledged it.
    CancellationAcknowledged,
    /// Task completed successfully.
    Completed,
    /// Task completed with cancellation as its final state.
    Cancelled,
    /// Task completed with a typed failure.
    Failed,
}

impl WorkerTaskStatus {
    /// Returns a stable label suitable for structured logs and tests.
    pub const fn label(self) -> &'static str {
        match self {
            Self::Queued => "queued",
            Self::Running => "running",
            Self::Progress => "progress",
            Self::CancellationRequested => "cancellation-requested",
            Self::CancellationAcknowledged => "cancellation-acknowledged",
            Self::Completed => "completed",
            Self::Cancelled => "cancelled",
            Self::Failed => "failed",
        }
    }

    /// Returns true when no further events are expected for the task.
    pub const fn is_terminal(self) -> bool {
        matches!(self, Self::Completed | Self::Cancelled | Self::Failed)
    }
}

impl fmt::Display for WorkerTaskStatus {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(self.label())
    }
}

/// Shared envelope emitted by every background worker.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerEvent {
    /// Stable task identity and high-level kind metadata.
    pub task: WorkerTask,
    /// Current lifecycle/status for this event.
    pub status: WorkerTaskStatus,
    /// Typed event-specific payload.
    pub payload: WorkerPayload,
}

impl WorkerEvent {
    /// Creates a typed worker event envelope.
    pub fn new(task: WorkerTask, status: WorkerTaskStatus, payload: WorkerPayload) -> Self {
        Self {
            task,
            status,
            payload,
        }
    }

    /// Creates a running lifecycle event.
    pub fn running(task: WorkerTask) -> Self {
        Self::new(task, WorkerTaskStatus::Running, WorkerPayload::None)
    }

    /// Creates a progress event with optional text and counts.
    pub fn progress(task: WorkerTask, progress: WorkerProgress) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::Progress,
            WorkerPayload::Progress(progress),
        )
    }

    /// Creates a successful completion event.
    pub fn completed(task: WorkerTask, payload: WorkerPayload) -> Self {
        Self::new(task, WorkerTaskStatus::Completed, payload)
    }

    /// Creates a typed failure event.
    pub fn failed(task: WorkerTask, failure: WorkerFailure) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::Failed,
            WorkerPayload::Error(failure),
        )
    }

    /// Creates a cancellation-request event.
    pub fn cancellation_requested(task: WorkerTask, cancellation: WorkerCancellation) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::CancellationRequested,
            WorkerPayload::Cancellation(cancellation),
        )
    }

    /// Creates a cancellation-acknowledgement event.
    pub fn cancellation_acknowledged(task: WorkerTask, cancellation: WorkerCancellation) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::CancellationAcknowledged,
            WorkerPayload::Cancellation(cancellation),
        )
    }

    /// Creates the final cancelled completion event.
    pub fn cancelled(task: WorkerTask, cancellation: WorkerCancellation) -> Self {
        Self::new(
            task,
            WorkerTaskStatus::Cancelled,
            WorkerPayload::Cancellation(cancellation),
        )
    }
}

/// Optional progress text and counts for a worker task.
#[derive(Debug, Default, Clone, PartialEq, Eq, Hash)]
pub struct WorkerProgress {
    /// Optional safe text for status labels or logs.
    pub message: Option<String>,
    /// Optional completed item count.
    pub current: Option<u64>,
    /// Optional total item count when it is cheap and meaningful to know.
    pub total: Option<u64>,
}

impl WorkerProgress {
    /// Creates an empty progress value with no text or counts.
    pub fn new() -> Self {
        Self::default()
    }

    /// Adds safe human-readable progress text.
    pub fn with_message(mut self, message: impl Into<String>) -> Self {
        self.message = Some(message.into());
        self
    }

    /// Adds optional current and total counts without implying percentages or ETA.
    pub const fn with_counts(mut self, current: Option<u64>, total: Option<u64>) -> Self {
        self.current = current;
        self.total = total;
        self
    }

    /// Returns true when this progress value has no text or counts.
    pub const fn is_empty(&self) -> bool {
        self.message.is_none() && self.current.is_none() && self.total.is_none()
    }
}

/// Safe text payload used by task-specific message variants.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct WorkerMessage {
    /// User-safe message text.
    pub safe_message: String,
}

impl WorkerMessage {
    /// Creates a safe worker message.
    pub fn new(safe_message: impl Into<String>) -> Self {
        Self {
            safe_message: safe_message.into(),
        }
    }
}

/// Typed worker failure with user-safe text separated from diagnostics.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct WorkerFailure {
    /// User-safe failure text suitable for UI status surfaces.
    pub safe_message: String,
    /// Optional diagnostic detail for logs or tests, never modal text.
    pub diagnostic: Option<String>,
}

impl WorkerFailure {
    /// Creates a worker failure from safe user-facing text.
    pub fn new(safe_message: impl Into<String>) -> Self {
        Self {
            safe_message: safe_message.into(),
            diagnostic: None,
        }
    }

    /// Adds diagnostic detail while preserving the safe message.
    pub fn with_diagnostic(mut self, diagnostic: impl Into<String>) -> Self {
        self.diagnostic = Some(diagnostic.into());
        self
    }

    /// Returns the safe user-facing failure message.
    pub fn safe_message(&self) -> &str {
        &self.safe_message
    }

    /// Returns optional diagnostic detail for structured logs and tests.
    pub fn diagnostic(&self) -> Option<&str> {
        self.diagnostic.as_deref()
    }
}

/// Cancellation payload for requested, acknowledged, and final-cancelled events.
#[derive(Debug, Default, Clone, PartialEq, Eq, Hash)]
pub struct WorkerCancellation {
    /// Optional safe cancellation text.
    pub message: Option<String>,
}

impl WorkerCancellation {
    /// Creates a cancellation payload.
    pub fn new(message: Option<String>) -> Self {
        Self { message }
    }

    /// Creates an empty cancellation payload.
    pub fn empty() -> Self {
        Self::default()
    }

    /// Creates a cancellation payload with safe text.
    pub fn with_message(message: impl Into<String>) -> Self {
        Self {
            message: Some(message.into()),
        }
    }
}

/// Typed payload variants carried by worker events.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum WorkerPayload {
    /// No additional payload is needed for this lifecycle event.
    None,
    /// Progress text and optional counts.
    Progress(WorkerProgress),
    /// Discovery-specific status or result text.
    Discovery(WorkerMessage),
    /// Scanner-specific status or result text.
    Scan(WorkerMessage),
    /// Patcher-specific status or result text.
    Patch(WorkerMessage),
    /// Download-specific status or result text.
    Download(WorkerMessage),
    /// Overview-specific snapshot, update, or desktop-action result.
    Overview(OverviewWorkerPayload),
    /// External process, tool, or desktop-action result.
    ExternalAction(ExternalActionPayload),
    /// Cancellation details.
    Cancellation(WorkerCancellation),
    /// User-safe failure plus optional diagnostics.
    Error(WorkerFailure),
    /// Generic status or result text.
    Generic(WorkerMessage),
}

/// Overview-specific worker payloads that must cross the UI handoff boundary intact.
#[derive(Debug, Clone, PartialEq, Eq)]
pub enum OverviewWorkerPayload {
    /// A full Overview refresh produced a render-ready snapshot.
    RefreshCompleted {
        /// Refresh request id used to reject stale worker results.
        refresh_id: u64,
        /// Owned snapshot produced off the UI thread.
        snapshot: Box<OverviewSnapshot>,
    },
    /// The update-check worker produced a final banner state.
    UpdateCheckCompleted {
        /// Refresh request id the update check was tied to.
        refresh_id: u64,
        /// Banner state safe for the Overview UI.
        update_banner: UpdateBannerState,
    },
    /// A URL/path action completed and may have produced a safe visible error.
    DesktopActionCompleted {
        /// Deferred action that was attempted.
        action: OverviewDeferredActionKind,
        /// Safe action error when the desktop adapter rejected the request.
        error: Option<OverviewActionError>,
    },
}

impl OverviewWorkerPayload {
    /// Creates a successful refresh payload.
    pub fn refresh_completed(refresh_id: u64, snapshot: OverviewSnapshot) -> Self {
        Self::RefreshCompleted {
            refresh_id,
            snapshot: Box::new(snapshot),
        }
    }

    /// Creates an update-check completion payload.
    pub fn update_check_completed(refresh_id: u64, update_banner: UpdateBannerState) -> Self {
        Self::UpdateCheckCompleted {
            refresh_id,
            update_banner,
        }
    }

    /// Creates a desktop-action completion payload.
    pub fn desktop_action_completed(
        action: OverviewDeferredActionKind,
        error: Option<OverviewActionError>,
    ) -> Self {
        Self::DesktopActionCompleted { action, error }
    }
}

/// High-level external operation source.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum ExternalActionKind {
    /// Desktop shell action such as opening a URL or path.
    Desktop,
    /// Child process or process-table action.
    Process,
    /// External tool launch action.
    Tool,
    /// Unknown external action retained for forward compatibility.
    Unknown,
}

impl ExternalActionKind {
    /// Returns a stable label suitable for structured logs and tests.
    pub const fn label(self) -> &'static str {
        match self {
            Self::Desktop => "desktop",
            Self::Process => "process",
            Self::Tool => "tool",
            Self::Unknown => "unknown",
        }
    }
}

/// Success or typed failure state for an external action payload.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum ExternalActionOutcome {
    /// The external action was handed off or completed successfully.
    Succeeded,
    /// The external action failed with a typed platform failure kind.
    Failed(PlatformErrorKind),
}

/// Worker payload for process/tool/desktop action results.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct ExternalActionPayload {
    /// High-level source of the external operation.
    pub action_kind: ExternalActionKind,
    /// Platform operation that was attempted.
    pub operation: PlatformOperation,
    /// User-selected or adapter-supplied target.
    pub target: String,
    /// Success or typed failure state.
    pub outcome: ExternalActionOutcome,
    /// Safe user-facing status text.
    pub safe_message: String,
}

impl ExternalActionPayload {
    /// Creates a successful external action payload.
    pub fn succeeded(
        action_kind: ExternalActionKind,
        operation: PlatformOperation,
        target: impl Into<String>,
        safe_message: impl Into<String>,
    ) -> Self {
        Self {
            action_kind,
            operation,
            target: target.into(),
            outcome: ExternalActionOutcome::Succeeded,
            safe_message: safe_message.into(),
        }
    }

    /// Creates a failed external action payload.
    pub fn failed(
        action_kind: ExternalActionKind,
        operation: PlatformOperation,
        target: impl Into<String>,
        kind: PlatformErrorKind,
        safe_message: impl Into<String>,
    ) -> Self {
        Self {
            action_kind,
            operation,
            target: target.into(),
            outcome: ExternalActionOutcome::Failed(kind),
            safe_message: safe_message.into(),
        }
    }

    /// Creates a failed external action payload from a typed platform error.
    pub fn from_platform_error(action_kind: ExternalActionKind, error: PlatformError) -> Self {
        let safe_message = error.user_message().to_owned();
        Self::failed(
            action_kind,
            error.operation,
            error.target,
            error.kind,
            safe_message,
        )
    }

    /// Returns true when the external action succeeded.
    pub const fn is_success(&self) -> bool {
        matches!(self.outcome, ExternalActionOutcome::Succeeded)
    }

    /// Returns the typed failure kind when the external action failed.
    pub const fn failure_kind(&self) -> Option<PlatformErrorKind> {
        match self.outcome {
            ExternalActionOutcome::Succeeded => None,
            ExternalActionOutcome::Failed(kind) => Some(kind),
        }
    }
}

impl From<DesktopActionResult> for ExternalActionPayload {
    fn from(result: DesktopActionResult) -> Self {
        let action_kind = match result.operation {
            PlatformOperation::OpenUrl | PlatformOperation::OpenPath => ExternalActionKind::Desktop,
            PlatformOperation::LaunchTool => ExternalActionKind::Tool,
            _ => ExternalActionKind::Unknown,
        };
        let outcome = match result.outcome {
            DesktopActionOutcome::Succeeded => ExternalActionOutcome::Succeeded,
            DesktopActionOutcome::Failed(kind) => ExternalActionOutcome::Failed(kind),
        };

        let safe_message = result.safe_message().to_owned();
        let operation = result.operation;
        let target = result.target;

        Self {
            action_kind,
            operation,
            target,
            outcome,
            safe_message,
        }
    }
}

/// Shared cancellation token passed to blocking worker closures.
#[derive(Debug, Clone, Default)]
pub struct CancellationToken {
    requested: Arc<AtomicBool>,
}

impl CancellationToken {
    /// Creates a cancellation token in the non-requested state.
    pub fn new() -> Self {
        Self::default()
    }

    /// Marks cancellation as requested.
    pub fn request_cancellation(&self) {
        self.requested.store(true, Ordering::SeqCst);
    }

    /// Returns whether cancellation has been requested.
    pub fn is_cancellation_requested(&self) -> bool {
        self.requested.load(Ordering::SeqCst)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn task_kinds_cover_required_background_categories() {
        let kinds = [
            WorkerTaskKind::Overview,
            WorkerTaskKind::Discovery,
            WorkerTaskKind::Scan,
            WorkerTaskKind::Patch,
            WorkerTaskKind::Download,
            WorkerTaskKind::ExternalProcess,
            WorkerTaskKind::Generic,
            WorkerTaskKind::Unknown,
        ];

        assert_eq!(
            kinds.map(WorkerTaskKind::label),
            [
                "overview",
                "discovery",
                "scan",
                "patch",
                "download",
                "external-process",
                "generic",
                "unknown",
            ]
        );
    }

    #[test]
    fn event_envelope_carries_task_status_and_typed_payload() {
        let task =
            WorkerTask::new("discover-game", WorkerTaskKind::Discovery).with_label("Discover game");
        let event = WorkerEvent::completed(
            task.clone(),
            WorkerPayload::Discovery(WorkerMessage::new("Discovery complete.")),
        );

        assert_eq!(event.task, task);
        assert_eq!(event.status, WorkerTaskStatus::Completed);
        assert!(event.status.is_terminal());
        assert!(matches!(event.payload, WorkerPayload::Discovery(_)));
    }

    #[test]
    fn overview_payload_carries_owned_snapshot_and_update_state() {
        let task = WorkerTask::new("overview-refresh-1", WorkerTaskKind::Overview);
        let snapshot = OverviewSnapshot::loading("Refreshing Overview...");
        let refresh = WorkerEvent::completed(
            task.clone(),
            WorkerPayload::Overview(OverviewWorkerPayload::refresh_completed(
                1,
                snapshot.clone(),
            )),
        );
        let update = WorkerEvent::completed(
            task,
            WorkerPayload::Overview(OverviewWorkerPayload::update_check_completed(
                1,
                UpdateBannerState::Disabled,
            )),
        );

        assert!(matches!(
            refresh.payload,
            WorkerPayload::Overview(OverviewWorkerPayload::RefreshCompleted {
                refresh_id: 1,
                snapshot: ref actual,
            }) if actual.as_ref() == &snapshot
        ));
        assert!(matches!(
            update.payload,
            WorkerPayload::Overview(OverviewWorkerPayload::UpdateCheckCompleted {
                refresh_id: 1,
                update_banner: UpdateBannerState::Disabled,
            })
        ));
    }

    #[test]
    fn progress_supports_optional_text_and_counts_without_percentage_requirements() {
        let text_only = WorkerProgress::new().with_message("Scanning Data folder");
        let counts_only = WorkerProgress::new().with_counts(Some(3), Some(10));
        let open_ended = WorkerProgress::new().with_counts(Some(7), None);

        assert_eq!(text_only.message.as_deref(), Some("Scanning Data folder"));
        assert_eq!(text_only.current, None);
        assert_eq!(counts_only.current, Some(3));
        assert_eq!(counts_only.total, Some(10));
        assert_eq!(open_ended.current, Some(7));
        assert_eq!(open_ended.total, None);
    }

    #[test]
    fn cancellation_request_acknowledgement_and_final_cancelled_are_distinct_events() {
        let task = WorkerTask::new("scan-cancel", WorkerTaskKind::Scan);
        let requested = WorkerEvent::cancellation_requested(
            task.clone(),
            WorkerCancellation::with_message("Cancel requested."),
        );
        let acknowledged = WorkerEvent::cancellation_acknowledged(
            task.clone(),
            WorkerCancellation::with_message("Worker stopping."),
        );
        let cancelled = WorkerEvent::cancelled(task, WorkerCancellation::with_message("Stopped."));

        assert_eq!(requested.status, WorkerTaskStatus::CancellationRequested);
        assert_eq!(
            acknowledged.status,
            WorkerTaskStatus::CancellationAcknowledged
        );
        assert_eq!(cancelled.status, WorkerTaskStatus::Cancelled);
        assert!(!requested.status.is_terminal());
        assert!(!acknowledged.status.is_terminal());
        assert!(cancelled.status.is_terminal());
    }

    #[test]
    fn desktop_action_results_flow_through_external_action_payloads() {
        let success =
            DesktopActionResult::success(PlatformOperation::OpenUrl, "https://example.invalid/cmt");
        let success_payload = ExternalActionPayload::from(success);

        assert_eq!(success_payload.action_kind, ExternalActionKind::Desktop);
        assert_eq!(success_payload.operation, PlatformOperation::OpenUrl);
        assert_eq!(success_payload.target, "https://example.invalid/cmt");
        assert!(success_payload.is_success());
        assert_eq!(success_payload.safe_message, "Opened URL.");

        let failure = DesktopActionResult::failure(PlatformError::command_failed(
            PlatformOperation::LaunchTool,
            r"C:\Tools\BSArch.exe",
            "raw OS diagnostic detail",
        ));
        let failure_payload = ExternalActionPayload::from(failure);

        assert_eq!(failure_payload.action_kind, ExternalActionKind::Tool);
        assert_eq!(failure_payload.operation, PlatformOperation::LaunchTool);
        assert_eq!(failure_payload.target, r"C:\Tools\BSArch.exe");
        assert_eq!(
            failure_payload.failure_kind(),
            Some(PlatformErrorKind::CommandFailed)
        );
        assert_eq!(failure_payload.safe_message, "Tool launch failed.");
        assert!(!failure_payload.safe_message.contains("raw OS"));
    }
}

//! Worker event handoff sinks.
//!
//! Background workers emit owned [`WorkerEvent`](crate::workers::events::WorkerEvent)
//! values through this module. Tests can use the recording sink, while UI code can
//! use the Slint event-loop sink so worker closures never mutate Slint models or
//! component handles directly.

use std::{
    fmt,
    sync::{Arc, Mutex},
};

use crate::workers::events::WorkerEvent;

/// Result type returned by worker handoff sinks.
pub type WorkerHandoffResult<T = ()> = Result<T, WorkerHandoffError>;

/// Typed handoff failure categories.
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash)]
pub enum WorkerHandoffErrorKind {
    /// The in-memory recording sink could not be locked.
    RecordingUnavailable,
    /// Slint rejected the event-loop handoff, usually because the loop is gone.
    SlintEventLoopUnavailable,
}

impl WorkerHandoffErrorKind {
    /// Returns a stable label suitable for structured logs and tests.
    pub const fn label(self) -> &'static str {
        match self {
            Self::RecordingUnavailable => "recording-unavailable",
            Self::SlintEventLoopUnavailable => "slint-event-loop-unavailable",
        }
    }
}

/// Failure emitted when a worker event cannot be handed to a sink.
#[derive(Debug, Clone, PartialEq, Eq)]
pub struct WorkerHandoffError {
    /// Typed failure category.
    pub kind: WorkerHandoffErrorKind,
    /// Safe user-facing message.
    pub safe_message: String,
    /// Optional diagnostic detail for logs or tests.
    pub diagnostic: Option<String>,
}

impl WorkerHandoffError {
    /// Creates a handoff error with a safe message.
    pub fn new(kind: WorkerHandoffErrorKind, safe_message: impl Into<String>) -> Self {
        Self {
            kind,
            safe_message: safe_message.into(),
            diagnostic: None,
        }
    }

    /// Adds diagnostic detail without changing the safe message.
    pub fn with_diagnostic(mut self, diagnostic: impl Into<String>) -> Self {
        self.diagnostic = Some(diagnostic.into());
        self
    }

    fn recording_poisoned(diagnostic: impl Into<String>) -> Self {
        Self::new(
            WorkerHandoffErrorKind::RecordingUnavailable,
            "Worker event recording is unavailable.",
        )
        .with_diagnostic(diagnostic)
    }

    fn slint_event_loop(diagnostic: impl Into<String>) -> Self {
        Self::new(
            WorkerHandoffErrorKind::SlintEventLoopUnavailable,
            "Worker event could not be delivered to the UI event loop.",
        )
        .with_diagnostic(diagnostic)
    }
}

impl fmt::Display for WorkerHandoffError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        write!(formatter, "{} ({})", self.safe_message, self.kind.label())
    }
}

impl std::error::Error for WorkerHandoffError {}

/// Sink trait used by worker code to emit owned events.
pub trait WorkerEventSink: Clone + Send + Sync + 'static {
    /// Emits one owned worker event.
    fn emit(&self, event: WorkerEvent) -> WorkerHandoffResult;
}

/// Test and diagnostics sink that stores all emitted events in memory.
#[derive(Debug, Clone, Default)]
pub struct RecordingEventSink {
    events: Arc<Mutex<Vec<WorkerEvent>>>,
}

impl RecordingEventSink {
    /// Creates an empty recording sink.
    pub fn new() -> Self {
        Self::default()
    }

    /// Returns a cloned snapshot of recorded events.
    pub fn events(&self) -> WorkerHandoffResult<Vec<WorkerEvent>> {
        self.events
            .lock()
            .map(|events| events.clone())
            .map_err(|error| WorkerHandoffError::recording_poisoned(error.to_string()))
    }

    /// Returns the number of recorded events.
    pub fn len(&self) -> WorkerHandoffResult<usize> {
        self.events
            .lock()
            .map(|events| events.len())
            .map_err(|error| WorkerHandoffError::recording_poisoned(error.to_string()))
    }

    /// Returns true when no events have been recorded.
    pub fn is_empty(&self) -> WorkerHandoffResult<bool> {
        self.len().map(|len| len == 0)
    }
}

impl WorkerEventSink for RecordingEventSink {
    fn emit(&self, event: WorkerEvent) -> WorkerHandoffResult {
        self.events
            .lock()
            .map(|mut events| events.push(event))
            .map_err(|error| WorkerHandoffError::recording_poisoned(error.to_string()))
    }
}

/// Slint event-loop sink for handing worker events to UI-owned state.
///
/// The handler runs on Slint's event loop. Worker code only sees this sink and
/// owned [`WorkerEvent`](crate::workers::events::WorkerEvent) values; it never
/// receives Slint component handles or model references.
#[derive(Clone)]
pub struct SlintEventLoopSink {
    handler: Arc<dyn Fn(WorkerEvent) + Send + Sync + 'static>,
}

impl SlintEventLoopSink {
    /// Creates a Slint event-loop sink from a UI-thread handler.
    pub fn new(handler: impl Fn(WorkerEvent) + Send + Sync + 'static) -> Self {
        Self {
            handler: Arc::new(handler),
        }
    }
}

impl fmt::Debug for SlintEventLoopSink {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter
            .debug_struct("SlintEventLoopSink")
            .field("handler", &"<event-loop handler>")
            .finish()
    }
}

impl WorkerEventSink for SlintEventLoopSink {
    fn emit(&self, event: WorkerEvent) -> WorkerHandoffResult {
        let handler = Arc::clone(&self.handler);
        slint::invoke_from_event_loop(move || {
            handler(event);
        })
        .map_err(|error| WorkerHandoffError::slint_event_loop(error.to_string()))
    }
}

